-- Ver quantos ativos da última sync ficaram sem match (estão na tabela anbima_assets mas não em spread_analysis)
SELECT COUNT(*) as total_anbima FROM anbima_assets WHERE dataReferencia = '2026-03-30';

-- Ver distribuição de scoreMatch nos que passaram
SELECT MIN(scoreMatch) as min_score, MAX(scoreMatch) as max_score, AVG(scoreMatch) as avg_score, COUNT(*) as total
FROM spread_analysis WHERE dataReferencia = '2026-03-30';

